   661→
   662→	public requestAllDiagnostics() {
   663→		for (const buffer of this.syncedBuffers.allBuffers) {
   664→			if (this.shouldValidate(buffer)) {
   665→				this.pendingDiagnostics.set(buffer.resource, Date.now());
   666→			}
   667→		}
